class Solution(object):
    def finalPositionOfSnake(self, n, commands):
        r = c = 0
        for cmd in commands:
            if cmd == 'UP': r -= 1
            elif cmd == 'DOWN': r += 1
            elif cmd == 'LEFT': c -= 1
            elif cmd == 'RIGHT': c += 1
        return r * n + c
